            long total = maxXorSum + b;
            if (total > maxResult) {
                maxResult = total;
            }
        }
        return maxResult;
    }

    private static long computeMaxXORSum(long[] elements) {
        Set<String> dp = new HashSet<>();
        dp.add("0,0");
        for (long num : elements) {
            Set<String> newDp = new HashSet<>();
            for (String s : dp) {
                String[] parts = s.split(",");
                long a = Long.parseLong(parts[0]);
                long c = Long.parseLong(parts[1]);
                // Assign num to A
                String newA = (a ^ num) + "," + c;
                newDp.add(newA);
